import{_ as e,o,c as n,ag as r}from"./chunks/framework.BpaS1AlU.js";const h=JSON.parse('{"title":"Core concepts","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts.md","filePath":"guide/concepts.md"}'),a={name:"guide/concepts.md"};function s(d,t,c,g,i,l){return o(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="core-concepts" tabindex="-1">Core concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core concepts&quot;">​</a></h1><p>Short glossary for Omega on Flutter. For diagrams and longer examples, see <a href="https://github.com/yefersonSegura/omega_architecture/blob/main/doc/GUIA.md" target="_blank" rel="noreferrer">GUIA.md</a>.</p><table tabindex="0"><thead><tr><th>Concept</th><th>Role</th></tr></thead><tbody><tr><td><strong>OmegaChannel</strong></td><td>Event bus: <code>emit</code> / <code>events</code>, optional <code>namespace(&#39;auth&#39;)</code> per module.</td></tr><tr><td><strong>OmegaEvent</strong></td><td>Something that happened (<code>name</code> + <code>payload</code>), often typed.</td></tr><tr><td><strong>OmegaIntent</strong></td><td>Something the UI wants (<code>login</code>, <code>navigate.home</code>, …); handled by flows / navigator.</td></tr><tr><td><strong>OmegaFlow</strong></td><td>Orchestrates a feature: <code>onIntent</code>, <code>onEvent</code>, emits expressions and navigation intents.</td></tr><tr><td><strong>OmegaAgent</strong></td><td>Subscribes to the channel; <strong>behavior</strong> maps reactions to imperative work (HTTP, storage).</td></tr><tr><td><strong>Flow manager</strong></td><td>Decides which flow is <strong>running</strong> and delivers intents.</td></tr><tr><td><strong>OmegaNavigator</strong></td><td>Maps navigation intents to <strong>routes</strong> and arguments for screens.</td></tr><tr><td><strong>Expressions</strong></td><td>Stream of UI-facing state from a flow (loading, error, data).</td></tr></tbody></table><p><strong>One sentence:</strong> the UI says what it wants (<strong>intent</strong>); the channel carries <strong>events</strong>; <strong>flows</strong> and <strong>agents</strong> decide what happens; the UI only reflects <strong>expressions</strong> and route changes.</p><p>Next: <strong><a href="./data-flow.html">Data flow</a></strong>.</p>',5)])])}const m=e(a,[["render",s]]);export{h as __pageData,m as default};
